const canvas=document.getElementById("qrCanvas");function generateQR(){const e=document.getElementById("urlInput").value.trim(),t=document.getElementById("downloads"),n=document.getElementById("downloadPng"),a=document.getElementById("downloadJpg"),o=document.getElementById("qrSize");let d=parseInt(o.value,10);if((Number.isNaN(d)||d<300)&&(d=300,o.value=300),d>2048){const e=prompt("Recommended maximum size is 2048px for performance reasons.\n\nYou entered: "+d+"px\n\nYou can adjust it here:",d);if(null===e)d=2048;else{const t=parseInt(e,10);d=!Number.isNaN(t)&&t>=300?t:2048}o.value=d}e?QRCode.toCanvas(canvas,e,{width:d,margin:2,color:{dark:"#000000",light:"#00000000"}},(function(e){e?alert("Could not generate QR code."):(n.href=canvas.toDataURL("image/png"),n.download="qr-code.png",a.href=createJpgWithWhiteBackground(canvas),a.download="qr-code.jpg",t.style.display="block")})):alert("Please enter a link.")}function createJpgWithWhiteBackground(e){const t=document.createElement("canvas"),n=t.getContext("2d");return t.width=e.width,t.height=e.height,n.fillStyle="#ffffff",n.fillRect(0,0,t.width,t.height),n.drawImage(e,0,0),t.toDataURL("image/jpeg",.95)}document.getElementById("year").textContent=(new Date).getFullYear();